//! Capability-lease process supervisor.
//!
//! A run is time-boxed by a lease (the UCAN `exp`). While the child runs, the
//! supervisor periodically asks the authority to RENEW; if a renewal is denied
//! (capability revoked) or the lease expires without renewal, or a hard ceiling
//! is exceeded, the child's whole process group is killed. This is the
//! "timebox by default + renew the lease + kill rogue processes" model.

use std::os::unix::process::CommandExt;
use std::process::{Child, Command};
use std::time::{Duration, Instant};

/// Outcome of a renewal attempt.
pub enum RenewOutcome {
    /// Lease extended; supervise until `new_deadline`.
    Renewed { new_deadline: Instant },
    /// Capability is no longer valid (revoked/expired); kill the process.
    Denied(String),
}

/// The authority consulted at each renewal tick. Implementors re-check the
/// delegation + revocation store and decide whether the lease may continue.
pub trait LeaseAuthority {
    fn renew(&self) -> RenewOutcome;
}

#[derive(Debug, Clone)]
pub struct LeaseConfig {
    /// Initial lease duration.
    pub ttl: Duration,
    /// How long before the deadline to attempt a renewal.
    pub renew_at: Duration,
    /// Absolute wall-clock cap regardless of renewals (None = unbounded).
    pub hard_ceiling: Option<Duration>,
    /// Supervisor poll interval.
    pub poll: Duration,
    /// Grace period between SIGTERM and SIGKILL when killing.
    pub kill_grace: Duration,
}

impl Default for LeaseConfig {
    fn default() -> Self {
        let ttl = Duration::from_secs(60);
        Self {
            ttl,
            renew_at: ttl / 2,
            hard_ceiling: None,
            poll: Duration::from_millis(250),
            kill_grace: Duration::from_secs(2),
        }
    }
}

#[derive(Debug, PartialEq)]
pub enum LeaseExit {
    Exited(i32),
    KilledExpired,
    KilledRevoked(String),
    KilledCeiling,
}

/// Configure a command to start in its own process group so the supervisor can
/// signal the whole subtree (sandbox-exec + the sandboxed child) at once.
pub fn spawn_in_process_group(cmd: &mut Command) {
    unsafe {
        cmd.pre_exec(|| {
            // New session/process group; the child becomes group leader (pgid == pid).
            if libc::setsid() == -1 {
                // Fall back to setpgid if already a session leader.
                let _ = libc::setpgid(0, 0);
            }
            Ok(())
        });
    }
}

fn signal_group(pid: i32, sig: i32) {
    unsafe {
        // Negative pid => deliver to the whole process group.
        libc::kill(-pid, sig);
    }
}

fn kill_group(child: &mut Child, grace: Duration) {
    let pid = child.id() as i32;
    signal_group(pid, libc::SIGTERM);
    let start = Instant::now();
    while start.elapsed() < grace {
        if matches!(child.try_wait(), Ok(Some(_))) {
            return;
        }
        std::thread::sleep(Duration::from_millis(50));
    }
    signal_group(pid, libc::SIGKILL);
    let _ = child.wait();
}

fn exit_code(status: std::process::ExitStatus) -> i32 {
    status.code().unwrap_or_else(|| {
        use std::os::unix::process::ExitStatusExt;
        // 128 + signal, matching shell convention.
        status.signal().map(|s| 128 + s).unwrap_or(-1)
    })
}

/// Run the supervisor loop over an already-spawned child.
pub fn supervise(
    mut child: Child,
    authority: &dyn LeaseAuthority,
    cfg: &LeaseConfig,
) -> std::io::Result<LeaseExit> {
    let started = Instant::now();
    let mut deadline = started + cfg.ttl;
    let mut last_attempt: Option<Instant> = None;
    let min_attempt_gap = cfg.renew_at / 2;

    loop {
        if let Some(status) = child.try_wait()? {
            return Ok(LeaseExit::Exited(exit_code(status)));
        }
        let now = Instant::now();

        if let Some(ceiling) = cfg.hard_ceiling {
            if now.duration_since(started) >= ceiling {
                kill_group(&mut child, cfg.kill_grace);
                return Ok(LeaseExit::KilledCeiling);
            }
        }

        if now >= deadline {
            kill_group(&mut child, cfg.kill_grace);
            return Ok(LeaseExit::KilledExpired);
        }

        // In the renewal window?
        let in_window = deadline.checked_duration_since(now).map(|d| d <= cfg.renew_at).unwrap_or(true);
        let due = last_attempt
            .map(|t| now.duration_since(t) >= min_attempt_gap)
            .unwrap_or(true);
        if in_window && due {
            last_attempt = Some(now);
            match authority.renew() {
                RenewOutcome::Renewed { new_deadline } => {
                    if new_deadline > now {
                        deadline = new_deadline;
                    }
                }
                RenewOutcome::Denied(reason) => {
                    kill_group(&mut child, cfg.kill_grace);
                    return Ok(LeaseExit::KilledRevoked(reason));
                }
            }
        }

        std::thread::sleep(cfg.poll);
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicUsize, Ordering};

    struct AlwaysRenew(Duration);
    impl LeaseAuthority for AlwaysRenew {
        fn renew(&self) -> RenewOutcome {
            RenewOutcome::Renewed { new_deadline: Instant::now() + self.0 }
        }
    }

    struct AlwaysDeny;
    impl LeaseAuthority for AlwaysDeny {
        fn renew(&self) -> RenewOutcome {
            RenewOutcome::Denied("revoked".into())
        }
    }

    struct DenyAfter(AtomicUsize, usize);
    impl LeaseAuthority for DenyAfter {
        fn renew(&self) -> RenewOutcome {
            let n = self.0.fetch_add(1, Ordering::SeqCst);
            if n >= self.1 {
                RenewOutcome::Denied("revoked".into())
            } else {
                RenewOutcome::Renewed { new_deadline: Instant::now() + Duration::from_millis(300) }
            }
        }
    }

    fn sleep_cmd(secs: &str) -> Child {
        let mut c = Command::new("/bin/sleep");
        c.arg(secs);
        spawn_in_process_group(&mut c);
        c.spawn().unwrap()
    }

    fn fast_cfg(ttl_ms: u64) -> LeaseConfig {
        LeaseConfig {
            ttl: Duration::from_millis(ttl_ms),
            renew_at: Duration::from_millis(ttl_ms / 2),
            hard_ceiling: None,
            poll: Duration::from_millis(20),
            kill_grace: Duration::from_millis(200),
        }
    }

    #[test]
    fn fast_process_exits_clean() {
        let child = sleep_cmd("0.1");
        let exit = supervise(child, &AlwaysRenew(Duration::from_secs(10)), &fast_cfg(500)).unwrap();
        assert_eq!(exit, LeaseExit::Exited(0));
    }

    #[test]
    fn survives_with_renewal() {
        // ttl 200ms but always renewed far ahead; sleep 0.6s should finish.
        let child = sleep_cmd("0.6");
        let exit = supervise(child, &AlwaysRenew(Duration::from_secs(10)), &fast_cfg(200)).unwrap();
        assert_eq!(exit, LeaseExit::Exited(0));
    }

    #[test]
    fn killed_when_denied() {
        let child = sleep_cmd("10");
        let exit = supervise(child, &AlwaysDeny, &fast_cfg(200)).unwrap();
        assert!(matches!(exit, LeaseExit::KilledRevoked(_)));
    }

    #[test]
    fn killed_when_expired_no_renew() {
        // renew_at 0 => never enters the window before deadline; long sleep -> expired kill.
        let child = sleep_cmd("10");
        let cfg = LeaseConfig {
            ttl: Duration::from_millis(150),
            renew_at: Duration::from_millis(0),
            hard_ceiling: None,
            poll: Duration::from_millis(20),
            kill_grace: Duration::from_millis(200),
        };
        let exit = supervise(child, &AlwaysRenew(Duration::from_secs(10)), &cfg).unwrap();
        assert_eq!(exit, LeaseExit::KilledExpired);
    }

    #[test]
    fn revoked_mid_run_kills() {
        // renews a few times then denies -> revoked kill before sleep 10 ends.
        let child = sleep_cmd("10");
        let exit = supervise(child, &DenyAfter(AtomicUsize::new(0), 2), &fast_cfg(200)).unwrap();
        assert!(matches!(exit, LeaseExit::KilledRevoked(_)));
    }

    #[test]
    fn hard_ceiling_kills() {
        let child = sleep_cmd("10");
        let cfg = LeaseConfig {
            ttl: Duration::from_secs(10),
            renew_at: Duration::from_secs(5),
            hard_ceiling: Some(Duration::from_millis(300)),
            poll: Duration::from_millis(20),
            kill_grace: Duration::from_millis(200),
        };
        let exit = supervise(child, &AlwaysRenew(Duration::from_secs(10)), &cfg).unwrap();
        assert_eq!(exit, LeaseExit::KilledCeiling);
    }
}
